1	"use client";
2	
3	import { useRouter } from "next/navigation";
4	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
5	
6	import type {
7	  PublicAskKind,
8	  PublicAskResponse,
9	  PublicAskResult,
10	} from "@/lib/publicAsk";
11	
12	/**
13	 * Public inquiry-search box. Reused on the homepage (compact mode) and
14	 * on `/ask` (full mode). Pure retrieval — never freeform-generates
15	 * text. Posts to `/api/public/ask` and renders the bucketed result
16	 * lists with methodology + confidence pills.
17	 *
18	 * Keyboard contract:
19	 *   - `/` from anywhere on the page focuses the input (skipped if the
20	 *     user is already typing into a form).
21	 *   - Arrow Up / Arrow Down moves through the flat result list once a
22	 *     response has rendered.
23	 *   - Enter on a focused result navigates to that result's href.
24	 *   - Submit (Enter in the input) runs a query and, in compact mode,
25	 *     sends the reader to `/ask?q=...` so the dedicated page can host
26	 *     the keyboard-driven results UI.
27	 */
28	
29	type Mode = "compact" | "full";
30	
31	const KIND_ORDER: PublicAskKind[] = [
32	  "conclusion",
33	  "article",
34	  "opinion",
35	  "open_question",
36	];
37	
38	const KIND_LABEL: Record<PublicAskKind, string> = {
39	  conclusion: "CONCLUSIONS",
40	  article: "ARTICLES",
41	  opinion: "OPINIONS · CURRENTS",
42	  open_question: "OPEN QUESTIONS",
43	};
44	
45	const SUBMIT_DEBOUNCE_MS = 150;
46	
47	export default function PublicAskBox({
48	  mode = "compact",
49	  initialQuery = "",
50	  autoFocus = false,
51	}: {
52	  mode?: Mode;
53	  initialQuery?: string;
54	  autoFocus?: boolean;
55	}) {
56	  const router = useRouter();
57	  const inputRef = useRef<HTMLInputElement>(null);
58	  const [query, setQuery] = useState(initialQuery);
59	  const [pending, setPending] = useState(false);
60	  const [error, setError] = useState<string | null>(null);
61	  const [response, setResponse] = useState<PublicAskResponse | null>(null);
62	  const [activeIdx, setActiveIdx] = useState(-1);
63	
64	  const flatResults = useMemo(() => flattenResults(response), [response]);
65	
66	  const submit = useCallback(
67	    async (raw: string) => {
68	      const trimmed = raw.trim();
69	      if (trimmed.length < 3) {
70	        setResponse(null);
71	        setError(null);
72	        return;
73	      }
74	      if (mode === "compact") {
75	        router.push(`/ask?q=${encodeURIComponent(trimmed)}`);
76	        return;
77	      }
78	      setPending(true);
79	      setError(null);
80	      try {
81	        const res = await fetch("/api/public/ask", {
82	          method: "POST",
83	          headers: { "Content-Type": "application/json" },
84	          body: JSON.stringify({ query: trimmed }),
85	        });
86	        if (!res.ok) {
87	          const body = (await res.json().catch(() => null)) as { error?: string } | null;
88	          throw new Error(body?.error ?? `Request failed (${res.status})`);
89	        }
90	        const json = (await res.json()) as PublicAskResponse;
91	        setResponse(json);
92	        setActiveIdx(-1);
93	      } catch (err) {
94	        setError(err instanceof Error ? err.message : "Retrieval failed");
95	        setResponse(null);
96	      } finally {
97	        setPending(false);
98	      }
99	    },
100	    [mode, router],
101	  );
102	
103	  // Run the initial query on mount in full mode.
104	  useEffect(() => {
105	    if (mode !== "full") return;
106	    if (initialQuery.trim().length < 3) return;
107	    let cancelled = false;
108	    const handle = window.setTimeout(() => {
109	      if (cancelled) return;
110	      void submit(initialQuery);
111	    }, SUBMIT_DEBOUNCE_MS);
112	    return () => {
113	      cancelled = true;
114	      window.clearTimeout(handle);
115	    };
116	    // submit is stable per-mode; intentional that we don't re-run on
117	    // every keystroke (we do that via the input handler instead).
118	    // eslint-disable-next-line react-hooks/exhaustive-deps
119	  }, [mode, initialQuery]);
120	
121	  // Slash-to-focus.
122	  useEffect(() => {
123	    function onKey(event: KeyboardEvent) {
124	      if (event.key !== "/") return;
125	      const target = event.target as HTMLElement | null;
126	      if (target && (target.tagName === "INPUT" || target.tagName === "TEXTAREA" || target.isContentEditable)) {
127	        return;
128	      }
129	      event.preventDefault();
130	      inputRef.current?.focus();
131	    }
132	    window.addEventListener("keydown", onKey);
133	    return () => window.removeEventListener("keydown", onKey);
134	  }, []);
135	
136	  // Arrow / enter navigation when results are present.
137	  useEffect(() => {
138	    if (mode !== "full") return;
139	    if (flatResults.length === 0) return;
140	
141	    function onKey(event: KeyboardEvent) {
142	      if (event.key === "ArrowDown") {
143	        event.preventDefault();
144	        setActiveIdx((idx) => Math.min(flatResults.length - 1, idx + 1));
145	      } else if (event.key === "ArrowUp") {
146	        event.preventDefault();
147	        setActiveIdx((idx) => Math.max(-1, idx - 1));
148	      } else if (event.key === "Enter") {
149	        const target = event.target as HTMLElement | null;
150	        if (target?.tagName === "INPUT") return;
151	        if (activeIdx < 0 || activeIdx >= flatResults.length) return;
152	        event.preventDefault();
153	        const href = flatResults[activeIdx].href;
154	        router.push(href);
155	      }
156	    }
157	    window.addEventListener("keydown", onKey);
158	    return () => window.removeEventListener("keydown", onKey);
159	  }, [mode, flatResults, activeIdx, router]);
160	
161	  return (
162	    <section
163	      aria-labelledby="public-ask-heading"
164	      data-testid="public-ask-box"
