3	import Link from "next/link";
4	import { usePathname } from "next/navigation";
5	import { useEffect, useId, useRef, useState } from "react";
6	
7	import ThemeToggle from "./ThemeToggle";
8	
9	/**
10	 * Mobile drawer for the public site nav. Below 720px the PublicHeader
11	 * collapses its inline link list and exposes a single hamburger control;
12	 * tapping it mounts this drawer.
13	 *
14	 * Closes on:
15	 *   - explicit close button
16	 *   - tap on the scrim outside the drawer body
17	 *   - Escape key
18	 *   - route change (pathname effect)
19	 *
20	 * Focus is moved into the drawer on open and trapped between the first
21	 * and last focusable element, then restored to the trigger on close.
22	 */
23	
24	const FOCUSABLE_SELECTOR =
25	  'a[href], button:not([disabled]), [tabindex]:not([tabindex="-1"])';
26	
27	export default function MobileNavDrawer({ authed }: { authed: boolean }) {
28	  const [open, setOpen] = useState(false);
29	  const triggerRef = useRef<HTMLButtonElement | null>(null);
30	  const drawerRef = useRef<HTMLDivElement | null>(null);
31	  const pathname = usePathname();
32	  const drawerId = useId().replace(/:/g, "");
33	
34	  useEffect(() => {
35	    if (!open) return;
36	    setOpen(false);
37	    // pathname-only dependency: close on route change.
38	    // eslint-disable-next-line react-hooks/exhaustive-deps
39	  }, [pathname]);
40	
41	  useEffect(() => {
42	    if (!open) return;
43	
44	    const previouslyFocused =
45	      typeof document !== "undefined" ? document.activeElement : null;
46	
47	    const onKeyDown = (event: KeyboardEvent) => {
48	      if (event.key === "Escape") {
49	        event.preventDefault();
50	        setOpen(false);
51	        return;
52	      }
53	      if (event.key !== "Tab") return;
54	      const drawer = drawerRef.current;
55	      if (!drawer) return;
56	      const focusables = Array.from(
57	        drawer.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR),
58	      ).filter((el) => !el.hasAttribute("disabled") && el.tabIndex !== -1);
59	      if (!focusables.length) {
60	        event.preventDefault();
61	        drawer.focus();
62	        return;
63	      }
64	      const first = focusables[0];
65	      const last = focusables[focusables.length - 1];
66	      const active = document.activeElement;
67	      if (event.shiftKey && active === first) {
68	        event.preventDefault();
69	        last.focus();
70	      } else if (!event.shiftKey && active === last) {
71	        event.preventDefault();
72	        first.focus();
73	      }
74	    };
75	
76	    const previousOverflow = document.body.style.overflow;
77	    document.body.style.overflow = "hidden";
78	    document.addEventListener("keydown", onKeyDown);
79	
80	    const frame = window.requestAnimationFrame(() => {
81	      const drawer = drawerRef.current;
82	      if (!drawer) return;
83	      const [first] = Array.from(
84	        drawer.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR),
85	      ).filter((el) => !el.hasAttribute("disabled") && el.tabIndex !== -1);
86	      (first ?? drawer).focus();
87	    });
88	
89	    return () => {
90	      window.cancelAnimationFrame(frame);
91	      document.removeEventListener("keydown", onKeyDown);
92	      document.body.style.overflow = previousOverflow;
93	      if (
94	        previouslyFocused &&
95	        previouslyFocused instanceof HTMLElement &&
96	        document.contains(previouslyFocused)
97	      ) {
98	        previouslyFocused.focus();
99	      } else {
100	        triggerRef.current?.focus();
101	      }
102	    };
103	  }, [open]);
104	
105	  return (
106	    <>
107	      <button
108	        aria-controls={drawerId}
109	        aria-expanded={open}
110	        aria-label={open ? "Close navigation menu" : "Open navigation menu"}
111	        className="public-nav-trigger"
112	        data-testid="public-nav-trigger"
113	        onClick={() => setOpen((prev) => !prev)}
114	        ref={triggerRef}
115	        type="button"
116	      >
117	        <span aria-hidden="true" className="public-nav-trigger-bars">
118	          <span />
119	          <span />
120	          <span />
121	        </span>
122	      </button>
123	
124	      {open ? (
125	        <div
126	          aria-hidden={!open}
127	          className="public-nav-scrim"
128	          data-testid="public-nav-scrim"
129	          onClick={(event) => {
130	            if (event.target === event.currentTarget) setOpen(false);
131	          }}
132	        >
133	          <div
134	            aria-label="Public navigation"
135	            aria-modal="true"
136	            className="public-nav-drawer"
137	            data-testid="public-nav-drawer"
138	            id={drawerId}
139	            onKeyDown={(event) => event.stopPropagation()}
140	            ref={drawerRef}
141	            role="dialog"
142	            tabIndex={-1}
143	          >
144	            <div className="public-nav-drawer-head">
145	              <span className="mono public-nav-drawer-title">Theseus</span>
146	              <button
147	                aria-label="Close navigation menu"
