                          >
                            {s.id.slice(0, 10)}
                          </code>
                          {preview}
                        </>
                      );
                      return (
                        <li
                          key={s.id}
                          style={{
                            display: "flex",
                            gap: "0.9rem",
                            fontSize: "0.82rem",
                            lineHeight: 1.5,
                            color: "var(--parchment-dim)",
                          }}
                        >
                          <span
                            className="mono"
                            style={{
                              fontSize: "0.58rem",
                              letterSpacing: "0.1em",
                              color: "var(--amber-dim)",
                              flexShrink: 0,
                              width: "5.5rem",
                            }}
                          >
                            [{String(i + 1).padStart(2, "0")}] {s.tier}
                          </span>
                          {href ? (
                            <Link
                              href={href}
                              rel="noopener"
                              style={{
                                color: "var(--parchment-dim)",
                                textDecoration: "none",
                              }}
                              target="_blank"
                              title={preview}
                            >
                              {body}
                            </Link>
                          ) : (
                            <span>{body}</span>
                          )}
                        </li>
                      );
                    })}
                  </ul>
                </section>
              )}
            </div>
          )}
        </article>
      )}
    </div>
  );
}

