}

function ResultRow({ item, active }: { item: PublicAskResult; active: boolean }) {
  return (
    <li
      data-testid="public-ask-result-row"
      data-active={active ? "true" : undefined}
      style={{
        background: active ? "rgba(205, 151, 67, 0.08)" : "transparent",
