      </div>
      <p
        style={{
          color: "var(--parchment)",
          fontFamily: "'EB Garamond', serif",
          fontSize: "0.97rem",
          lineHeight: 1.5,
          margin: "0.55rem 0 0",
        }}
      >
        {item.snippet}
      </p>
    </li>
  );
}

function pillStyle(color: string): React.CSSProperties {
  return {
    border: `1px solid ${color}`,
    borderRadius: 999,
    color,
    padding: "0.18rem 0.55rem",
  };
}

